-- в”Ђв”Ђ AlienVault в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$AlienVault was a cybersecurity and threat intelligence company known for its Unified Security Management (USM) platform and the open-source OSSIM SIEM; it was acquired by AT&amp;T in 2018, rebranded as AT&amp;T Cybersecurity, and its products are now operated by LevelBlue, a standalone managed cybersecurity company launched in 2024.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$1000 plus employees (LevelBlue, global)$q$, company_size),
  headquarters = COALESCE($q$Dallas, Texas, United States (LevelBlue)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AlienVault (LevelBlue) 2026: USM and OSSIM Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$AlienVault is now part of LevelBlue, the AT&amp;T-linked cybersecurity firm. Learn the history, USM and OSSIM products, and current branding for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AlienVault is the original name of a threat intelligence and security management company whose products have since changed corporate ownership multiple times, which is important for anyone researching the brand today. The underlying technology traces back to 2003, when developers Dominique Karg, Julio Casal, and later Alberto Roman and Ignacio Cabrera began OSSIM (Open Source Security Information Management), a free, open-source SIEM (security information and event management) project. In 2007, this team founded AlienVault as a commercial company headquartered in San Mateo, California, with additional offices in Madrid and Granada, Spain, and Cork, Ireland, building a paid product called Unified Security Management (USM) on top of the OSSIM foundation. USM combined asset discovery, vulnerability assessment, intrusion detection, behavioral monitoring, and SIEM correlation into a single platform, and AlienVault also operated the Open Threat Exchange (OTX), a crowdsourced threat intelligence sharing community. AlienVault raised roughly 116 million dollars in venture funding over its life as an independent company before AT&amp;T Communications acquired it in a deal announced in July 2018 and completed in August 2018; AlienVault was folded into AT&amp;T and rebranded as AT&amp;T Cybersecurity, continuing to sell USM (later USM Anywhere, a cloud-native SIEM and XDR platform) alongside AT&amp;T's broader managed security services. The most recent major change occurred in May 2024, when AT&amp;T spun off its cybersecurity services business into LevelBlue, a new standalone company formed as a joint venture between AT&amp;T and private equity firm WillJam Ventures, with WillJam taking majority ownership and AT&amp;T retaining a minority stake and board seat; LevelBlue is headquartered in Dallas, Texas, employs over 1,000 people across roughly 10 countries, and is led by WillJam Ventures founder Robert McCullen. As part of this transition, LevelBlue announced the retirement of the free, open-source OSSIM product, ending vendor updates, maintenance, and security patches as of December 31, 2024, in order to concentrate resources on its commercial USM Anywhere open XDR platform and broader managed detection and response (MDR), consulting, and threat intelligence services. So while the alienvault.com domain still exists and redirects to AT&amp;T Cybersecurity and LevelBlue properties, the AlienVault name today is best understood as a legacy brand: its technology and customer base now live under LevelBlue, and prospective buyers evaluating 'AlienVault' products in 2026 are effectively evaluating LevelBlue's USM Anywhere and managed cybersecurity portfolio, sold on a custom, quote-based enterprise pricing model typical of managed security service providers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '737c8013-5fb0-4340-91e1-aff65a109a1e';

