-- в”Ђв”Ђ AllRatesToday в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$AllRatesToday is a developer-focused REST API providing real-time and historical currency exchange rates for over 160 currencies, plus a free web-based currency converter and rate comparison tools.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$$4.99/month (Small plan, billed as EUR 4.99/month)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AllRatesToday Review 2026: Free Currency Exchange API$q$, seo_title),
  seo_meta_description = COALESCE($q$AllRatesToday offers a free and paid REST API for real-time and historical exchange rates across 160 plus currencies. See plans, features, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AllRatesToday is a currency exchange rate data service built primarily as a developer API, offering real-time and historical foreign exchange rates for more than 160 currencies through a REST API, official SDKs (JavaScript/TypeScript, Python, PHP, and a React component library), and a consumer-facing currency converter tool on its website. Its rates are sourced from institutional data providers including Reuters (Refinitiv) and interbank market feeds, with the company stating that exchange rates are refreshed roughly every 60 seconds and that it targets 99.99 percent uptime, backed by Cloudflare infrastructure. The product is aimed at developers and businesses embedding currency conversion into e-commerce checkout flows, finance dashboards, travel applications, accounting software, and any system that needs to display or calculate amounts across multiple currencies, and it also publishes a public currency-converter page and rate-comparison content (for example comparing money transfer providers for pairs like EUR to USD) aimed at everyday consumers. AllRatesToday follows a freemium pricing structure: a Free plan offers one API key with a rate limit of 10 requests per minute, real-time and latest rates only, and is intended for non-commercial use with no credit card required. Paid tiers scale from there: a Small plan at roughly 4.99 euros per month (or 49.99 euros per year) includes 5,000 requests per month, one API key, historical rate access, and permission for commercial use; a Medium plan, the provider's recommended tier, costs roughly 9.99 euros per month (99.99 euros annually) and raises the limit to 10,000 requests per month with unlimited rate access and the full Convert endpoint; and a Large plan at roughly 49.99 euros per month (499 euros annually) supports 100,000 requests per month, three API keys, and priority email support, aimed at higher-traffic production applications. Annual billing across paid tiers offers roughly a 17 percent discount, equivalent to about two free months. Concrete public details about the company behind AllRatesToday, such as a specific founding year, headquarters location, or team size, were not found in available sources; the site's footer displays a broad copyright range, but this alone is not a reliable indicator of the company's actual founding date, so that detail is treated as unverified rather than stated as fact. As a currency-data API, AllRatesToday competes with services like Open Exchange Rates, exchangerate-api.com, Fixer, and similar forex data providers, differentiating primarily on its combination of a genuinely free entry tier, multiple official SDKs, and relatively low-cost paid plans for smaller applications.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cfd17a20-216c-4f15-a6b7-1804992894a8';

